#include <torch/library.h>
#include <torch/extension.h>
#include "pytorch_npu_helper.hpp"

at::Tensor conv3d_square_input_asym_impl_npu(const at::Tensor& x, const at::Tensor& weight) {
    TORCH_CHECK(x.dim() == 5, \"x must be 5D [N,C,W,H,D]\");
    TORCH_CHECK(weight.dim() == 5, \"weight must be 5D [Cout,Cin,Kw,Kh,Kd]\");
    TORCH_CHECK(x.size(1) == weight.size(1), \"Cin mismatch\");

    const auto N = x.size(0);
    const auto Cout = weight.size(0);
    const auto W = x.size(2);
    const auto H = x.size(3);
    const auto D = x.size(4);
    const auto Kw = weight.size(2);
    const auto Kh = weight.size(3);
    const auto Kd = weight.size(4);
    TORCH_CHECK(W >= Kw && H >= Kh && D >= Kd, \"Kernel larger than input without padding\");

    const auto Wo = W - Kw + 1;
    const auto Ho = H - Kh + 1;
    const auto Do = D - Kd + 1;

    at::Tensor result = at::empty({N, Cout, Wo, Ho, Do}, x.options());
    EXEC_NPU_CMD(aclnnConvStandard3dSquareInputAsymmetricKernelCustom, x, weight, result);
    return result;
}

